import classNames from "classnames";
import * as React from "react";

export default function Button({
  className,
  as = "anchor",
  type = "button",
  size = "md",
  href = "#",
  fill = true,
  disabled = false,
  onClick,
  children,
}) {
  const commonClasses = classNames(
    "inline-block rounded-lg border-2 text-center ring-gray-200 ring-offset-2 transition focus-visible:ring-2",

    size === "sm" && "px-4 py-2",
    size === "md" && "px-5 py-2.5",

    fill && "border-transparent bg-white text-black",
    !fill && "border-white bg-black text-white",

    as === "anchor" && "hover:brightness-95",
    as === "button" && "enabled:hover:brightness-95",
    "disabled:cursor-not-allowed disabled:brightness-50",

    className,
  );

  if (as === "anchor")
    return (
      <a className={commonClasses} href={href}>
        {children}
      </a>
    );

  return (
    <button
      type={type}
      className={commonClasses}
      disabled={disabled}
      onClick={onClick}
    >
      {children}
    </button>
  );
}
